#pragma OPENCL EXTENSION cl_khr_fp64 : enable

__kernel void find_nearest_point_kernel(
    __global const float* features,   // Flattened features array: npoints * nfeatures
    __global const float* clusters,   // Flattened clusters array: nclusters * nfeatures
    __global int* membership,         // membership array: npoints
    __global float* partial_new_centers, // partial sums: nthreads * nclusters * nfeatures
    __global int* partial_new_centers_len, // partial counts: nthreads * nclusters
    const int npoints,
    const int nfeatures,
    const int nclusters,
    const int tid,
    __global float* delta_array       // delta per thread
    )
{
    int i = get_global_id(0);
    if (i >= npoints) return;

    // Find nearest cluster
    int nearest_index = 0;
    float min_dist = FLT_MAX;

    for (int c = 0; c < nclusters; c++) {
        float dist = 0.0f;
        for (int f = 0; f < nfeatures; f++) {
            float diff = features[i * nfeatures + f] - clusters[c * nfeatures + f];
            dist += diff * diff;
        }
        if (dist < min_dist) {
            min_dist = dist;
            nearest_index = c;
        }
    }

    // Check if membership changed
    int old_membership = membership[i];
    if (old_membership != nearest_index) {
        // Atomically add 1.0 to delta for this thread
        atomic_add(&delta_array[tid], 1.0f);
    }
    membership[i] = nearest_index;

    // Accumulate partial sums for new centers
    // partial_new_centers_len[tid * nclusters + nearest_index] += 1;
    atomic_inc(&partial_new_centers_len[tid * nclusters + nearest_index]);

    for (int f = 0; f < nfeatures; f++) {
        // atomic add to partial_new_centers[tid * nclusters * nfeatures + nearest_index * nfeatures + f]
        // OpenCL 2.0 supports atomic_add on floats with atomic_float type, but for compatibility, use atomic_add on ints with bitcast or use atomic_add on floats if supported.
        // Here we assume atomic_add on floats is supported (OpenCL 2.0).
        atomic_add(&partial_new_centers[tid * nclusters * nfeatures + nearest_index * nfeatures + f], features[i * nfeatures + f]);
    }
}

__kernel void reduce_new_centers(
    __global float* new_centers,          // nclusters * nfeatures
    __global int* new_centers_len,        // nclusters
    __global float* partial_new_centers,  // nthreads * nclusters * nfeatures
    __global int* partial_new_centers_len,// nthreads * nclusters
    const int nthreads,
    const int nclusters,
    const int nfeatures
    )
{
    int c = get_global_id(0);
    if (c >= nclusters) return;

    int sum_len = 0;
    for (int t = 0; t < nthreads; t++) {
        int len = partial_new_centers_len[t * nclusters + c];
        sum_len += len;
        partial_new_centers_len[t * nclusters + c] = 0;
        for (int f = 0; f < nfeatures; f++) {
            new_centers[c * nfeatures + f] += partial_new_centers[t * nclusters * nfeatures + c * nfeatures + f];
            partial_new_centers[t * nclusters * nfeatures + c * nfeatures + f] = 0.0f;
        }
    }
    new_centers_len[c] = sum_len;
}

__kernel void update_clusters(
    __global float* clusters,          // nclusters * nfeatures
    __global float* new_centers,       // nclusters * nfeatures
    __global int* new_centers_len,     // nclusters
    const int nclusters,
    const int nfeatures
    )
{
    int c = get_global_id(0);
    if (c >= nclusters) return;

    int len = new_centers_len[c];
    if (len > 0) {
        for (int f = 0; f < nfeatures; f++) {
            clusters[c * nfeatures + f] = new_centers[c * nfeatures + f] / (float)len;
            new_centers[c * nfeatures + f] = 0.0f;
        }
    }
    new_centers_len[c] = 0;
}
